"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { 
  Clock, 
  Calendar,
  Plus,
  Trash2,
  Save,
  X,
  Check
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { useToast } from "@/components/ui/use-toast";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

type TimeSlot = {
  start: string;
  end: string;
};

type DaySchedule = {
  enabled: boolean;
  slots: TimeSlot[];
};

type WeekSchedule = {
  [key: string]: DaySchedule;
};

type BlockedDate = {
  id: string;
  date: string;
  reason: string;
};

const DAYS = [
  { key: "monday", label: "Monday" },
  { key: "tuesday", label: "Tuesday" },
  { key: "wednesday", label: "Wednesday" },
  { key: "thursday", label: "Thursday" },
  { key: "friday", label: "Friday" },
  { key: "saturday", label: "Saturday" },
  { key: "sunday", label: "Sunday" },
];

const TIME_OPTIONS = [
  "12:00 AM", "12:30 AM", "1:00 AM", "1:30 AM", "2:00 AM", "2:30 AM",
  "3:00 AM", "3:30 AM", "4:00 AM", "4:30 AM", "5:00 AM", "5:30 AM",
  "6:00 AM", "6:30 AM", "7:00 AM", "7:30 AM", "8:00 AM", "8:30 AM",
  "9:00 AM", "9:30 AM", "10:00 AM", "10:30 AM", "11:00 AM", "11:30 AM",
  "12:00 PM", "12:30 PM", "1:00 PM", "1:30 PM", "2:00 PM", "2:30 PM",
  "3:00 PM", "3:30 PM", "4:00 PM", "4:30 PM", "5:00 PM", "5:30 PM",
  "6:00 PM", "6:30 PM", "7:00 PM", "7:30 PM", "8:00 PM", "8:30 PM",
  "9:00 PM", "9:30 PM", "10:00 PM", "10:30 PM", "11:00 PM", "11:30 PM",
];

const STORAGE_KEY = "providerAvailability";
const BLOCKED_DATES_KEY = "providerBlockedDates";

const defaultSchedule: WeekSchedule = {
  monday: { enabled: true, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
  tuesday: { enabled: true, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
  wednesday: { enabled: true, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
  thursday: { enabled: true, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
  friday: { enabled: true, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
  saturday: { enabled: false, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
  sunday: { enabled: false, slots: [{ start: "9:00 AM", end: "5:00 PM" }] },
};

const ManageAvailability = () => {
  const [schedule, setSchedule] = useState<WeekSchedule>(defaultSchedule);
  const [blockedDates, setBlockedDates] = useState<BlockedDate[]>([]);
  const [isBlockDateDialogOpen, setIsBlockDateDialogOpen] = useState(false);
  const [newBlockedDate, setNewBlockedDate] = useState("");
  const [newBlockedReason, setNewBlockedReason] = useState("");
  const [hasChanges, setHasChanges] = useState(false);
  const { toast } = useToast();

  // Load saved schedule and blocked dates
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setSchedule(JSON.parse(saved));
      } catch (error) {
        console.error("Failed to load schedule", error);
      }
    }

    const savedBlocked = localStorage.getItem(BLOCKED_DATES_KEY);
    if (savedBlocked) {
      try {
        setBlockedDates(JSON.parse(savedBlocked));
      } catch (error) {
        console.error("Failed to load blocked dates", error);
      }
    }
  }, []);

  const toggleDay = (day: string) => {
    setSchedule(prev => ({
      ...prev,
      [day]: {
        ...prev[day],
        enabled: !prev[day].enabled,
      },
    }));
    setHasChanges(true);
  };

  const addTimeSlot = (day: string) => {
    setSchedule(prev => ({
      ...prev,
      [day]: {
        ...prev[day],
        slots: [...prev[day].slots, { start: "9:00 AM", end: "5:00 PM" }],
      },
    }));
    setHasChanges(true);
  };

  const removeTimeSlot = (day: string, index: number) => {
    setSchedule(prev => ({
      ...prev,
      [day]: {
        ...prev[day],
        slots: prev[day].slots.filter((_, i) => i !== index),
      },
    }));
    setHasChanges(true);
  };

  const updateTimeSlot = (day: string, index: number, field: "start" | "end", value: string) => {
    setSchedule(prev => ({
      ...prev,
      [day]: {
        ...prev[day],
        slots: prev[day].slots.map((slot, i) =>
          i === index ? { ...slot, [field]: value } : slot
        ),
      },
    }));
    setHasChanges(true);
  };

  const saveSchedule = () => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(schedule));
    setHasChanges(false);
    toast({
      title: "Schedule Saved",
      description: "Your availability has been updated successfully.",
    });
  };

  const resetSchedule = () => {
    setSchedule(defaultSchedule);
    setHasChanges(true);
    toast({
      title: "Schedule Reset",
      description: "Your schedule has been reset to default hours.",
    });
  };

  const addBlockedDate = () => {
    if (!newBlockedDate) {
      toast({
        title: "Date Required",
        description: "Please select a date to block.",
        variant: "destructive",
      });
      return;
    }

    const newBlocked: BlockedDate = {
      id: Date.now().toString(),
      date: newBlockedDate,
      reason: newBlockedReason || "Not available",
    };

    const updated = [...blockedDates, newBlocked];
    setBlockedDates(updated);
    localStorage.setItem(BLOCKED_DATES_KEY, JSON.stringify(updated));

    setNewBlockedDate("");
    setNewBlockedReason("");
    setIsBlockDateDialogOpen(false);

    toast({
      title: "Date Blocked",
      description: `${newBlockedDate} has been blocked.`,
    });
  };

  const removeBlockedDate = (id: string) => {
    const updated = blockedDates.filter(d => d.id !== id);
    setBlockedDates(updated);
    localStorage.setItem(BLOCKED_DATES_KEY, JSON.stringify(updated));

    toast({
      title: "Date Unblocked",
      description: "The date has been removed from blocked dates.",
    });
  };

  const copySchedule = (fromDay: string) => {
    const sourceSchedule = schedule[fromDay];
    const updatedSchedule = { ...schedule };
    
    DAYS.forEach(day => {
      if (day.key !== fromDay) {
        updatedSchedule[day.key] = {
          enabled: sourceSchedule.enabled,
          slots: sourceSchedule.slots.map(slot => ({ ...slot })),
        };
      }
    });

    setSchedule(updatedSchedule);
    setHasChanges(true);
    toast({
      title: "Schedule Copied",
      description: `${DAYS.find(d => d.key === fromDay)?.label} schedule applied to all days.`,
    });
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold mb-2">Manage Availability</h1>
          <p className="text-muted-foreground">Set your working hours and block specific dates</p>
        </div>
        <div className="flex gap-2">
          {hasChanges && (
            <Button variant="outline" onClick={resetSchedule}>
              Reset
            </Button>
          )}
          <Button 
            onClick={saveSchedule}
            disabled={!hasChanges}
            style={{ background: hasChanges ? 'linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)' : '', color: hasChanges ? 'white' : '' }}
          >
            <Save className="h-4 w-4 mr-2" />
            Save Changes
          </Button>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="h-12 w-12 rounded-full bg-green-100 dark:bg-green-900/20 flex items-center justify-center">
                <Check className="h-6 w-6 text-green-600" />
              </div>
              <div>
                <p className="text-2xl font-bold">
                  {Object.values(schedule).filter(d => d.enabled).length}
                </p>
                <p className="text-sm text-muted-foreground">Active Days</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="h-12 w-12 rounded-full bg-orange-100 dark:bg-orange-900/20 flex items-center justify-center">
                <X className="h-6 w-6 text-orange-600" />
              </div>
              <div>
                <p className="text-2xl font-bold">{blockedDates.length}</p>
                <p className="text-sm text-muted-foreground">Blocked Dates</p>
              </div>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <div className="h-12 w-12 rounded-full bg-blue-100 dark:bg-blue-900/20 flex items-center justify-center">
                <Clock className="h-6 w-6 text-blue-600" />
              </div>
              <div>
                <p className="text-2xl font-bold">
                  {Object.values(schedule)
                    .filter(d => d.enabled)
                    .reduce((acc, d) => acc + d.slots.length, 0)}
                </p>
                <p className="text-sm text-muted-foreground">Time Slots</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Weekly Schedule */}
      <Card>
        <CardHeader>
          <CardTitle>Weekly Schedule</CardTitle>
          <p className="text-sm text-muted-foreground mt-1">
            Set your available hours for each day of the week
          </p>
        </CardHeader>
        <CardContent className="space-y-4">
          {DAYS.map((day) => (
            <div key={day.key} className="space-y-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Switch
                    checked={schedule[day.key].enabled}
                    onCheckedChange={() => toggleDay(day.key)}
                  />
                  <Label className="text-base font-semibold">{day.label}</Label>
                </div>
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => copySchedule(day.key)}
                    disabled={!schedule[day.key].enabled}
                  >
                    Copy to All
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => addTimeSlot(day.key)}
                    disabled={!schedule[day.key].enabled}
                  >
                    <Plus className="h-4 w-4 mr-1" />
                    Add Slot
                  </Button>
                </div>
              </div>

              {schedule[day.key].enabled && (
                <div className="ml-11 space-y-2">
                  {schedule[day.key].slots.map((slot, index) => (
                    <div key={index} className="flex items-center gap-2">
                      <Select
                        value={slot.start}
                        onValueChange={(value) => updateTimeSlot(day.key, index, "start", value)}
                      >
                        <SelectTrigger className="w-[140px]">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          {TIME_OPTIONS.map((time) => (
                            <SelectItem key={time} value={time}>
                              {time}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <span className="text-muted-foreground">to</span>
                      <Select
                        value={slot.end}
                        onValueChange={(value) => updateTimeSlot(day.key, index, "end", value)}
                      >
                        <SelectTrigger className="w-[140px]">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          {TIME_OPTIONS.map((time) => (
                            <SelectItem key={time} value={time}>
                              {time}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      {schedule[day.key].slots.length > 1 && (
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => removeTimeSlot(day.key, index)}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      )}
                    </div>
                  ))}
                </div>
              )}

              {day.key !== "sunday" && <div className="border-b border-border" />}
            </div>
          ))}
        </CardContent>
      </Card>

      {/* Blocked Dates */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Blocked Dates</CardTitle>
              <p className="text-sm text-muted-foreground mt-1">
                Block specific dates when you're not available
              </p>
            </div>
            <Button onClick={() => setIsBlockDateDialogOpen(true)}>
              <Plus className="h-4 w-4 mr-2" />
              Block Date
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {blockedDates.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <Calendar className="h-12 w-12 mx-auto mb-3 opacity-50" />
              <p>No blocked dates yet</p>
              <p className="text-sm">Click "Block Date" to add unavailable dates</p>
            </div>
          ) : (
            <div className="space-y-2">
              {blockedDates
                .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
                .map((blocked) => (
                  <div
                    key={blocked.id}
                    className="flex items-center justify-between p-3 rounded-lg border border-border hover:bg-muted/50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <div className="h-10 w-10 rounded-full bg-red-100 dark:bg-red-900/20 flex items-center justify-center">
                        <Calendar className="h-5 w-5 text-red-600" />
                      </div>
                      <div>
                        <p className="font-medium">
                          {new Date(blocked.date).toLocaleDateString(undefined, {
                            weekday: "long",
                            year: "numeric",
                            month: "long",
                            day: "numeric",
                          })}
                        </p>
                        <p className="text-sm text-muted-foreground">{blocked.reason}</p>
                      </div>
                    </div>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => removeBlockedDate(blocked.id)}
                    >
                      <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                  </div>
                ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Block Date Dialog */}
      <Dialog open={isBlockDateDialogOpen} onOpenChange={setIsBlockDateDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Block a Date</DialogTitle>
            <DialogDescription>
              Select a date when you won't be available for bookings
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label htmlFor="blocked-date">Date</Label>
              <Input
                id="blocked-date"
                type="date"
                value={newBlockedDate}
                onChange={(e) => setNewBlockedDate(e.target.value)}
                min={new Date().toISOString().split("T")[0]}
              />
            </div>
            <div>
              <Label htmlFor="blocked-reason">Reason (Optional)</Label>
              <Input
                id="blocked-reason"
                placeholder="e.g., Vacation, Personal day, etc."
                value={newBlockedReason}
                onChange={(e) => setNewBlockedReason(e.target.value)}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsBlockDateDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={addBlockedDate} style={{ background: 'linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)', color: 'white' }}>
              Block Date
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default ManageAvailability;
